query:
DELETE c1 FROM categories c1
INNER JOIN categories c2
  ON c1.userId = c2.userId AND c1.clientId = c2.clientId AND c1.id > c2.id;

DELETE h1 FROM habits h1
INNER JOIN habits h2
  ON h1.userId = h2.userId AND h1.clientId = h2.clientId AND h1.id > h2.id;

DELETE ci1 FROM checkIns ci1
INNER JOIN checkIns ci2
  ON ci1.userId = ci2.userId AND ci1.habitClientId = ci2.habitClientId AND ci1.date = ci2.date AND ci1.id > ci2.id;

